using System.Text.Json;
using System.Text.Json.Serialization.Metadata;

// --- Set up options with the default (reflection-based) resolver ---
var options = new JsonSerializerOptions
{
    TypeInfoResolver = new DefaultJsonTypeInfoResolver()
};

// 1️⃣  Strongly-typed retrieval: returns JsonTypeInfo<T> directly
JsonTypeInfo<Person> typed = options.GetTypeInfo<Person>();
Console.WriteLine($"Got JsonTypeInfo<{typed.Type.Name}> (strongly typed)");

// 2️⃣  Probe without throwing — TryGetTypeInfo returns false instead of throwing
if (options.TryGetTypeInfo(typeof(Person), out JsonTypeInfo? info))
{
    Console.WriteLine($"TryGetTypeInfo(Person) => found ({info!.Type.Name})");
}

// Now create options with an *empty* resolver so nothing is resolvable
var empty = new JsonSerializerOptions
{
    TypeInfoResolver = JsonTypeInfoResolver.Combine() // no resolvers
};

if (empty.TryGetTypeInfo(typeof(Person), out _))
{
    Console.WriteLine("TryGetTypeInfo(Person) => found (unexpected)");
}
else
{
    Console.WriteLine("TryGetTypeInfo(Person) => not found — no exception thrown!");
}

record Person(string Name, int Age);

